// Deduplicate Stream 1 by email — keep first occurrence only
const seen = new Set();
const deduped = [];

for (const item of items) {
  const email = item.json.email?.toLowerCase().trim();
  if (!seen.has(email)) {
    seen.add(email);
    deduped.push(item);
  }
}

console.log(`Stream 1: ${items.length} records in → ${deduped.length} after dedup`);
return deduped;

// Deduplicate Stream 2 by email — keep first occurrence only
const seen = new Set();
const deduped = [];

for (const item of items) {
  const email = item.json.email?.toLowerCase().trim();
  if (!seen.has(email)) {
    seen.add(email);
    deduped.push(item);
  }
}

console.log(`Stream 2: ${items.length} records in → ${deduped.length} after dedup`);
return deduped;

// Fully matched records — output clean unified object
return items.map(item => ({
  json: {
    name:           item.json.name,
    email:          item.json.email,
    company_domain: item.json.company_domain,
    status:         "matched"
  }
}));

// Unmatched records — email existed in one stream but not both
// Flag them for manual review or re-enrichment
return items.map(item => ({
  json: {
    name:           item.json.name   || null,
    email:          item.json.email,
    company_domain: item.json.company_domain || null,
    status:         "unmatched",
    reason:         !item.json.name ? "Email in Stream 2 only  - no name found" : "Email in Stream 1 only — no domain found"
  }
}));

// Stream 1: Names + Emails (simulating an ad platform or lead capture form)
